mapper.select:
SELECT a.*, b.name_level AS dept_name, c.name_level AS inst_name FROM sys_user a LEFT JOIN sys_dept b ON a.dept_id = b.dept_id LEFT JOIN sys_inst c ON a.inst_id = c.inst_id WHERE 1=1 AND a.state = 1
AND a.dept_id = #{deptId}
AND a.code = #{code}
AND a.name = #{name}
AND a.inst_id = #{instId}
AND a.is_deleted = 0 AND b.newlevel = 0 AND c.newlevel = 0

SELECT DISTINCT a.*, b.name_level AS dept_name FROM sys_user a LEFT JOIN sys_dept b ON a.dept_id = b.dept_id LEFT JOIN sys_role_user d on d.user_id = a.user_id WHERE 1=1 AND a.state = 1 AND d.is_deleted = 0
AND a.inst_id = #{instId}
AND b.dept_id = #{deptId}
AND d.role_id = #{roleId}
AND a.is_deleted = 0 AND b.is_deleted = 0
AND d.is_deleted = 0

SELECT u.user_id AS userId, u.dept_id AS deptId, u.name AS name, u.code AS code FROM sys_user u
u.is_deleted = 0
AND u.dept_id = #{deptId}
AND u.name LIKE CONCAT('%', #{name}, '%')
AND u.code = #{code}
AND EXISTS ( SELECT 1 FROM sys_post_user pu2 INNER JOIN sys_post p2 ON pu2.post_id = p2.post_id WHERE pu2.user_id = u.user_id AND pu2.is_deleted = 0 AND p2.is_deleted = 0 AND p2.name LIKE CONCAT('%', #{postName}, '%') )
